import React, { useState, useEffect } from 'react';
import {
  View,
  StyleSheet,
  ScrollView,
  Image,
  TouchableOpacity,
  Dimensions,
} from 'react-native';
import { Text, Card, Searchbar, Chip } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';

const { width } = Dimensions.get('window');

export default function HomeScreen({ navigation }) {
  const [searchQuery, setSearchQuery] = useState('');
  const [featuredProducts, setFeaturedProducts] = useState([]);

  useEffect(() => {
    loadFeaturedProducts();
  }, []);

  const loadFeaturedProducts = () => {
    // Mock data - replace with API call
    setFeaturedProducts([
      {
        id: 1,
        name: 'Fresh Tomatoes',
        price: 40,
        unit: 'kg',
        farmer: 'Rajesh Kumar',
        location: 'Pune',
        image: '🍅',
        rating: 4.5,
      },
      {
        id: 2,
        name: 'Organic Spinach',
        price: 30,
        unit: 'kg',
        farmer: 'Priya Sharma',
        location: 'Nashik',
        image: '🥬',
        rating: 4.8,
      },
      {
        id: 3,
        name: 'Fresh Carrots',
        price: 35,
        unit: 'kg',
        farmer: 'Amit Patil',
        location: 'Satara',
        image: '🥕',
        rating: 4.6,
      },
    ]);
  };

  const categories = [
    { name: 'Vegetables', icon: '🥬' },
    { name: 'Fruits', icon: '🍎' },
    { name: 'Grains', icon: '🌾' },
    { name: 'Dairy', icon: '🥛' },
    { name: 'Organic', icon: '🌱' },
  ];

  return (
    <ScrollView style={styles.container}>
      {/* Header */}
      <View style={styles.header}>
        <View>
          <Text style={styles.greeting}>Hello! 👋</Text>
          <Text style={styles.headerTitle}>What are you looking for?</Text>
        </View>
        <Icon name="bell-outline" size={24} color="#333" />
      </View>

      {/* Search Bar */}
      <Searchbar
        placeholder="Search products, farmers..."
        onChangeText={setSearchQuery}
        value={searchQuery}
        style={styles.searchBar}
      />

      {/* Categories */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Categories</Text>
        <ScrollView horizontal showsHorizontalScrollIndicator={false}>
          {categories.map((category, index) => (
            <TouchableOpacity key={index} style={styles.categoryCard}>
              <Text style={styles.categoryIcon}>{category.icon}</Text>
              <Text style={styles.categoryName}>{category.name}</Text>
            </TouchableOpacity>
          ))}
        </ScrollView>
      </View>

      {/* Featured Products */}
      <View style={styles.section}>
        <View style={styles.sectionHeader}>
          <Text style={styles.sectionTitle}>Featured Products</Text>
          <TouchableOpacity onPress={() => navigation.navigate('Products')}>
            <Text style={styles.seeAll}>See All</Text>
          </TouchableOpacity>
        </View>

        {featuredProducts.map((product) => (
          <Card
            key={product.id}
            style={styles.productCard}
            onPress={() => navigation.navigate('ProductDetail', { product })}
          >
            <View style={styles.productContent}>
              <View style={styles.productImage}>
                <Text style={styles.productEmoji}>{product.image}</Text>
              </View>
              <View style={styles.productInfo}>
                <Text style={styles.productName}>{product.name}</Text>
                <View style={styles.farmerInfo}>
                  <Icon name="account" size={14} color="#666" />
                  <Text style={styles.farmerName}> {product.farmer}</Text>
                </View>
                <View style={styles.locationInfo}>
                  <Icon name="map-marker" size={14} color="#666" />
                  <Text style={styles.location}> {product.location}</Text>
                </View>
                <View style={styles.ratingContainer}>
                  <Icon name="star" size={14} color="#FFC107" />
                  <Text style={styles.rating}> {product.rating}</Text>
                </View>
              </View>
              <View style={styles.priceContainer}>
                <Text style={styles.price}>₹{product.price}</Text>
                <Text style={styles.unit}>/{product.unit}</Text>
                <TouchableOpacity style={styles.addButton}>
                  <Icon name="plus" size={20} color="#fff" />
                </TouchableOpacity>
              </View>
            </View>
          </Card>
        ))}
      </View>

      {/* Nearby Farmers */}
      <View style={styles.section}>
        <Text style={styles.sectionTitle}>Nearby Farmers</Text>
        <Card style={styles.infoCard}>
          <View style={styles.infoContent}>
            <Icon name="map-marker-radius" size={40} color="#2E7D32" />
            <View style={styles.infoText}>
              <Text style={styles.infoTitle}>Find Local Farmers</Text>
              <Text style={styles.infoDescription}>
                Discover fresh produce from farmers near you
              </Text>
            </View>
          </View>
        </Card>
      </View>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: 20,
    paddingTop: 60,
    backgroundColor: '#fff',
  },
  greeting: {
    fontSize: 16,
